# Example task: Write a package main repository-pattern data layer (standard library only): a Store interface (Create/Get/List/Delete) over a User{ID,Name,Email} entity, plus a goroutine-safe in-memory MemStore backed by a map guarded by sync.RWMutex. Create returns a sentinel ErrExists on duplicate ID; Get/Delete return a sentinel ErrNotFound (matchable with errors.Is); List returns users sorted by ID for deterministic output. Add a compile-time `var _ Store = (*MemStore)(nil)` assertion.
```go
// Package main shows the repository pattern backends use for their data layer:
// a Store interface (so handlers/services depend on an abstraction, not a
// concrete DB) with a safe, concurrent in-memory implementation for tests and
// small deployments.
package main

import (
	"errors"
	"sort"
	"sync"
)

// ErrNotFound is returned when a lookup key is absent. Callers match it with
// errors.Is so the sentinel can be wrapped with context higher up.
var ErrNotFound = errors.New("not found")

// User is the stored entity.
type User struct {
	ID    string
	Name  string
	Email string
}

// Store is the abstraction the rest of the app depends on. A Postgres or SQLite
// implementation can be dropped in without touching callers.
type Store interface {
	Create(u User) error
	Get(id string) (User, error)
	List() []User
	Delete(id string) error
}

// ErrExists is returned by Create when the ID is already taken.
var ErrExists = errors.New("already exists")

// MemStore is a goroutine-safe in-memory Store.
type MemStore struct {
	mu    sync.RWMutex
	users map[string]User
}

// NewMemStore returns a ready-to-use empty store.
func NewMemStore() *MemStore {
	return &MemStore{users: make(map[string]User)}
}

func (s *MemStore) Create(u User) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[u.ID]; ok {
		return ErrExists
	}
	s.users[u.ID] = u
	return nil
}

func (s *MemStore) Get(id string) (User, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	if !ok {
		return User{}, ErrNotFound
	}
	return u, nil
}

// List returns every user ordered by ID so results are deterministic.
func (s *MemStore) List() []User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]User, 0, len(s.users))
	for _, u := range s.users {
		out = append(out, u)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}

func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[id]; !ok {
		return ErrNotFound
	}
	delete(s.users, id)
	return nil
}

// compile-time proof MemStore satisfies Store.
var _ Store = (*MemStore)(nil)

func main() {}
```
# Example task: Write an in-memory store package with sentinel errors ErrNotFound and ErrExists: Create returns ErrExists on a duplicate id, Get and Delete return ErrNotFound when the id is absent, List returns items sorted by id, using a concurrency-safe map.
```go
package store

import (
	"errors"
	"sort"
	"sync"
)

// Sentinel errors returned by the store; callers compare with errors.Is.
var (
	ErrNotFound = errors.New("not found")
	ErrExists   = errors.New("already exists")
)

// Task is the stored entity.
type Task struct {
	ID    string
	Title string
}

// MemStore is a concurrency-safe in-memory implementation of the store.
type MemStore struct {
	mu    sync.RWMutex
	tasks map[string]Task
}

// NewMemStore returns an initialised, empty store.
func NewMemStore() *MemStore {
	return &MemStore{tasks: make(map[string]Task)}
}

// Create inserts t, returning ErrExists if the ID is already present.
func (s *MemStore) Create(t Task) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[t.ID]; ok {
		return ErrExists
	}
	s.tasks[t.ID] = t
	return nil
}

// Get returns the task, or ErrNotFound if absent.
func (s *MemStore) Get(id string) (Task, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	t, ok := s.tasks[id]
	if !ok {
		return Task{}, ErrNotFound
	}
	return t, nil
}

// Delete removes the task, or returns ErrNotFound if absent.
func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[id]; !ok {
		return ErrNotFound
	}
	delete(s.tasks, id)
	return nil
}

// List returns all tasks sorted by ID.
func (s *MemStore) List() []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.tasks))
	for _, t := range s.tasks {
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}
```

