# Example task: Write a package main HTTP middleware system (standard library only): a Middleware type `func(http.Handler) http.Handler` and a Chain(h, mws...) helper where the FIRST middleware listed is the OUTERMOST layer. Include a Logging middleware that records method, path, resolved status code (via a statusRecorder that wraps http.ResponseWriter and defaults to 200) and latency, and a Recover middleware that turns a downstream panic into a 500 instead of crashing. Wire a /health route through the chain in main using an *http.Server.
```go
package main

import (
	"log"
	"net/http"
	"time"
)

// Middleware wraps an http.Handler to add one cross-cutting concern.
// Composing them keeps handlers focused on business logic.
type Middleware func(http.Handler) http.Handler

// Chain applies middlewares so the FIRST listed is the OUTERMOST layer:
// Chain(h, Logging, Recover) runs Logging(Recover(h)).
func Chain(h http.Handler, mws ...Middleware) http.Handler {
	for i := len(mws) - 1; i >= 0; i-- {
		h = mws[i](h)
	}
	return h
}

// statusRecorder captures the status code a downstream handler writes so the
// logging middleware can report it. It defaults to 200 like net/http does.
type statusRecorder struct {
	http.ResponseWriter
	status int
}

func (r *statusRecorder) WriteHeader(code int) {
	r.status = code
	r.ResponseWriter.WriteHeader(code)
}

// Logging records method, path, resolved status and latency for each request.
func Logging(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		rec := &statusRecorder{ResponseWriter: w, status: http.StatusOK}
		next.ServeHTTP(rec, r)
		log.Printf("%s %s -> %d (%s)", r.Method, r.URL.Path, rec.status, time.Since(start))
	})
}

// Recover converts a panic in any downstream handler into a 500 response
// instead of letting it crash the server.
func Recover(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if err := recover(); err != nil {
				log.Printf("panic: %v", err)
				http.Error(w, "internal server error", http.StatusInternalServerError)
			}
		}()
		next.ServeHTTP(w, r)
	})
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, _ *http.Request) {
		_, _ = w.Write([]byte("ok"))
	})

	handler := Chain(mux, Logging, Recover)
	srv := &http.Server{Addr: ":8080", Handler: handler}
	log.Fatal(srv.ListenAndServe())
}
```
# Example task: Write a package main bearer-token auth middleware (standard library only): Auth(token string) returning func(http.Handler) http.Handler that rejects requests without a valid `Authorization: Bearer <token>` header with 401 (constant-time compare) and passes valid requests to the wrapped next handler. Compose it as Auth(token)(mux).
```go
// Package main shows the standard bearer-token auth middleware shape: a
// constructor returning func(http.Handler) http.Handler so it composes with
// any mux, and a constant-time token compare.
package main

import (
	"crypto/subtle"
	"net/http"
)

// Auth returns middleware enforcing `Authorization: Bearer <token>` on every
// request. Constructed once with the expected token, it WRAPS the next
// handler — callers compose it as Auth(token)(mux), they never invoke the
// middleware with (w, r) directly:
//
//	protected := Auth("secret")(mux)
func Auth(token string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			got, ok := bearerToken(r)
			if !ok || subtle.ConstantTimeCompare([]byte(got), []byte(token)) != 1 {
				http.Error(w, "unauthorized", http.StatusUnauthorized)
				return
			}
			next.ServeHTTP(w, r)
		})
	}
}

func bearerToken(r *http.Request) (string, bool) {
	const prefix = "Bearer "
	h := r.Header.Get("Authorization")
	if len(h) <= len(prefix) || h[:len(prefix)] != prefix {
		return "", false
	}
	return h[len(prefix):], true
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})
	_ = Auth("secret")(mux) // wire into an http.Server in a real backend
}
```

